CREATE TABLE marketing_response (
    response_id NUMBER(6) PRIMARY KEY,
    passenger_id NUMBER(6) NOT NULL,
    promo_id NUMBER(3) NOT NULL,
    communication_channel VARCHAR2(20) NOT NULL,
    sent_date DATE NOT NULL,
    opened_flag CHAR(1),
    clicked_flag CHAR(1),
    booked_flag CHAR(1),
    reservation_id NUMBER(10)
);


COMMIT;